KpiCard.t-props:
{
                            bg: 'bg-primary',
                            name: 'Total Students',
                            value: state.students.value,
                            icon: 'bi-people'
                        }

{
                            bg: 'bg-success',
                            name: 'Total Teachers',
                            value: state.teachers.value,
                            icon: 'bi-person-badge'
                        }

{
                            bg: 'bg-warning',
                            name: 'Total Classes',
                            value: state.classes.value,
                            icon: 'bi-book'
                        }

{
                            bg: 'bg-danger',
                            name: 'Total Departments',
                            value: state.departments.value,
                            icon: 'bi-building'
                        }

ChartRenderer.t-props:
{
                                        type: 'doughnut',
                                        data: {
                                            labels: ['Present', 'Absent', 'Late'],
                                            datasets: [{
                                                label: 'Attendance '+ state.attendance_chart.total,
                                                data: [
                                                    state.attendance_chart.present,
                                                    state.attendance_chart.absent,
                                                    state.attendance_chart.late
                                                ],
                                                backgroundColor: [
                                                    '#28a745',
                                                    '#dc3545',
                                                    '#ffc107'
                                                ]
                                            }]
                                        },
                                        options: {
                                            plugins: {
                                                legend: { position: 'bottom' },
                                                title: { display: true, text: 'Attendance Summary', position: 'bottom'}
                                            }
                                        }
                                    }

{
                                        type: 'pie',
                                        data: {
                                            labels: ['Present', 'Absent'],
                                            datasets: [{
                                                label: 'Attendance Parcentage 100%',
                                                data: [
                                                    state.attendance_chart.attendance_parcent,
                                                    100 - state.attendance_chart.attendance_parcent,

                                                ],
                                                backgroundColor: [
                                                    '#28a745',
                                                    '#dc3545',

                                                ]
                                            }]
                                        },
                                        options: {
                                            plugins: {
                                                legend: { position: 'bottom' },
                                                title: { display: true, text: 'Attendance Parcentage', position: 'bottom'}
                                            }
                                        }
                                    }
